const item = $input.first().json;
const video_id = item.video_id || null;
if (!video_id) throw new Error('video_id não encontrado.');
return [{ json: { video_id } }];

// Preparar Montagem — builds complete FFmpeg montage script
const config = $('Configuração').first().json;
const videoId = $('Normalizar Input').first().json.video_id;

// Parse video data
const videoRaw = $('Ler Vídeo').all().map(i => i.json);
const video = Array.isArray(videoRaw[0]) ? videoRaw[0][0] : videoRaw[0];

// Parse cenas
const cenasRaw = $('Ler Cenas').all().map(i => i.json);
let cenas = Array.isArray(cenasRaw[0]) ? cenasRaw[0] : cenasRaw;
cenas = cenas.sort((a, b) => a.ordem - b.ordem);

const formato = video.formato || 'shorts';
const res = formato === 'shorts' ? '768x1344' : '1920x1080';
const resX = formato === 'shorts' ? 768 : 1920;
const resY = formato === 'shorts' ? 1344 : 1080;
const dir = '/tmp/m08/' + videoId;

// Storage URLs
const base = config.SUPABASE_URL + '/storage/v1/object/';
const finalPath = videoId + '/final.mp4';
const srtPath = videoId + '/legendas.srt';
const uploadFinal = base + 'videos-finais/' + finalPath;
const uploadSrt = base + 'videos-finais/' + srtPath;
const publicFinal = base + 'public/videos-finais/' + finalPath;
const publicSrt = base + 'public/videos-finais/' + srtPath;
const key = config.SUPABASE_SERVICE_KEY;

let s = 'set -e\n';
s += 'cd "' + dir + '"\n\n';

// === VERIFICAR FONTES ===
s += 'EATER_FONT=$(fc-list : file | grep -i eater | head -1 | cut -d: -f1 | sed "s/^ *//")\n';
s += 'CREEPSTER_FONT=$(fc-list : file | grep -i creepster | head -1 | cut -d: -f1 | sed "s/^ *//")\n';
s += '[ -z "$EATER_FONT" ] && echo "ERRO: Fonte Eater nao instalada" && exit 1\n';
s += '[ -z "$CREEPSTER_FONT" ] && echo "ERRO: Fonte Creepster nao instalada" && exit 1\n';
s += 'echo "Fontes OK"\n\n';

// === FASE 1: DOWNLOAD ===
s += 'echo "=== FASE 1: DOWNLOAD ==="\n';
for (const c of cenas) {
  if (c.tipo_cena === 'texto') continue;
  const n = c.numero;
  if (c.video_url) s += 'curl -sL -o "anim_' + n + '.mp4" "' + c.video_url + '"\n';
  if (c.efeito_url) s += 'curl -sL -o "fx_' + n + '.mp3" "' + c.efeito_url + '"\n';
}
s += 'echo "Downloads OK"\n\n';

// === FASE 2: PROCESSAR CENAS ===
s += 'echo "=== FASE 2: PROCESSAR CENAS ==="\n';
const fadeFiles = [];

for (let i = 0; i < cenas.length; i++) {
  const c = cenas[i];
  const n = c.numero;
  const isFirst = (i === 0);
  const isLast = (i === cenas.length - 1);
  const trans = c.transicao_entrada || 'dip_to_black';
  const ff = 'fade_' + n + '.mp4';
  fadeFiles.push(ff);

  s += '\n# Cena ' + n + ' (' + c.tipo_cena + ', ' + trans;
  if (isFirst) s += ', PRIMEIRA';
  if (isLast) s += ', ULTIMA';
  s += ')\n';

  if (c.tipo_cena === 'texto') {
    // Tela de texto — Creepster 52
    const dur = c.duracao_estimada || 3;

    // Escrever texto via heredoc (evita problemas de escaping)
    s += "cat > text_" + n + ".txt << 'TEXTEOF'\n";
    s += (c.narracao || '') + '\n';
    s += 'TEXTEOF\n';

    // Montar filtros de vídeo
    let vf = 'drawtext=textfile=text_' + n + '.txt:fontcolor=white:fontsize=52:x=(w-tw)/2:y=(h-th)/2:fontfile=$CREEPSTER_FONT:borderw=3:bordercolor=black:line_spacing=10:text_align=M+C';
    let afParts = [];
    if (trans === 'dip_to_black') {
      if (!isFirst) {
        vf += ',fade=t=in:st=0:d=0.5';
        afParts.push('afade=t=in:st=0:d=0.5');
      }
      if (!isLast) {
        const fo = (dur - 0.5).toFixed(4);
        vf += ',fade=t=out:st=' + fo + ':d=0.5';
        afParts.push('afade=t=out:st=' + fo + ':d=0.5');
      }
    }

    s += 'ffmpeg -y -f lavfi -i color=c=black:s=' + res + ':r=16:d=' + dur;
    s += ' -f lavfi -i anullsrc=r=44100:cl=stereo';
    s += ' -vf "' + vf + '"';
    if (afParts.length > 0) s += ' -af "' + afParts.join(',') + '"';
    s += ' -c:v libx264 -crf 18 -pix_fmt yuv420p -c:a aac -t ' + dur + ' ' + ff + '\n';

  } else {
    // Cena normal — sync vídeo + áudio
    if (c.efeito_url) {
      s += 'ffmpeg -y -i "anim_' + n + '.mp4" -i "fx_' + n + '.mp3" -map 0:v -map 1:a -c:v libx264 -crf 18 -c:a aac -shortest sync_' + n + '.mp4\n';
    } else {
      // Sem áudio — adicionar track silencioso
      s += 'ffmpeg -y -i "anim_' + n + '.mp4" -f lavfi -i anullsrc=r=44100:cl=stereo -map 0:v -map 1:a -c:v libx264 -crf 18 -c:a aac -shortest sync_' + n + '.mp4\n';
    }

    // Medir duração real
    s += 'DUR=$(ffprobe -v quiet -show_entries format=duration -of csv=p=0 sync_' + n + '.mp4)\n';

    if (trans === 'dip_to_black') {
      let vfParts = [];
      let afParts = [];

      if (!isFirst) {
        vfParts.push('fade=t=in:st=0:d=0.5');
        afParts.push('afade=t=in:st=0:d=0.5');
      }
      if (!isLast) {
        s += 'FOUT=$(python3 -c "print(round(float(\'${DUR}\') - 0.5, 4))")\n';
        vfParts.push('fade=t=out:st=${FOUT}:d=0.5');
        afParts.push('afade=t=out:st=${FOUT}:d=0.5');
      }

      if (vfParts.length > 0) {
        s += 'ffmpeg -y -i sync_' + n + '.mp4 -vf "' + vfParts.join(',') + '" -af "' + afParts.join(',') + '" -c:v libx264 -crf 18 -c:a aac ' + ff + '\n';
      } else {
        // dip_to_black sem fades (primeira + última, improvável)
        s += 'ffmpeg -y -i sync_' + n + '.mp4 -c:v libx264 -crf 18 -c:a aac ' + ff + '\n';
      }
    } else {
      // corte_seco — re-encode sem fades
      s += 'ffmpeg -y -i sync_' + n + '.mp4 -c:v libx264 -crf 18 -c:a aac ' + ff + '\n';
    }
  }

  s += 'echo "Cena ' + n + ' OK"\n';
}

s += '\n';

// === FASE 3: LEGENDAS ===
s += 'echo "=== FASE 3: LEGENDAS ==="\n';

// Dados das cenas para o gerador de legendas
