  n: c.numero,
  txt: (c.tipo_cena !== 'texto' && c.narracao) ? c.narracao : null,
  f: 'fade_' + c.numero + '.mp4'
}));

s += "cat > scenes_sub.json << 'JSONEOF'\n";
s += JSON.stringify(subData) + '\n';
s += 'JSONEOF\n\n';

