s += 'with open("scenes_sub.json") as f:\n';
s += '    scenes = json.load(f)\n';
s += '\n';
s += 'durations = {}\n';
s += 'for sc in scenes:\n';
s += '    ff = sc["f"]\n';
s += '    if os.path.exists(ff):\n';
