}
concatFilt += 'concat=n=' + fadeFiles.length + ':v=1:a=1[vout][aout]';
s += 'ffmpeg -y' + concatIn + ' -filter_complex "' + concatFilt + '" -map "[vout]" -map "[aout]" -c:v libx264 -crf 18 -c:a aac concatenado.mp4\n';
s += 'echo "Concat OK"\n\n';

