s += 'echo "=== FASE 5: EFEITOS VISUAIS ==="\n';
s += 'ffmpeg -y -i concatenado.mp4 -vf "noise=alls=10:allf=t,vignette=PI/4,curves=preset=darker" -c:v libx264 -crf 18 -c:a copy efeitos.mp4\n';
