// === FASE 6: EXPORT FINAL ===
s += 'echo "=== FASE 6: EXPORT FINAL ==="\n';
s += 'ffmpeg -y -i efeitos.mp4 -vf "ass=legendas.ass" -af "loudnorm=I=-16:TP=-1.5:LRA=11" -c:v libx264 -crf 23 -profile:v high -pix_fmt yuv420p -r 16 -c:a aac -b:a 128k -movflags +faststart final.mp4\n';
s += 'echo "Export OK"\n\n';

// === FASE 7: UPLOAD ===
s += 'echo "=== FASE 7: UPLOAD ==="\n';
s += 'curl -s -X POST "' + uploadFinal + '" ';
s += '-H "apikey: ' + key + '" ';
s += '-H "Authorization: Bearer ' + key + '" ';
s += '-H "Content-Type: video/mp4" ';
s += '-H "x-upsert: true" ';
s += '--data-binary @final.mp4\n\n';

s += 'curl -s -X POST "' + uploadSrt + '" ';
s += '-H "apikey: ' + key + '" ';
s += '-H "Authorization: Bearer ' + key + '" ';
s += '-H "Content-Type: text/plain" ';
s += '-H "x-upsert: true" ';
s += '--data-binary @legendas.srt\n\n';

s += 'echo "Upload OK"\n';
s += 'echo "SUCCESS"\n';

return [{ json: {
